class Solution:
    def shortestCompletingWord(self, licensePlate: str, words: List[str]) -> str:
        cnt = Counter(c.lower() for c in licensePlate if c.isalpha())
        best = ""
        for w in words:
            wc = Counter(w.lower())
            if all(wc[c] >= cnt[c] for c in cnt):
                if not best or len(w) < len(best): best = w
        return best

